/* --------------------------------- HELPERS --------------------------------- */
const genId = () => Math.random().toString(36).slice(2, 10) + Date.now().toString(36);

const DOC_META = {
  facture: { label: "Facture", plural: "Factures", icon: FileText, prefix: "FA" },
  devis: { label: "Devis", plural: "Devis", icon: ClipboardList, prefix: "DE" },
  commande: { label: "Commande", plural: "Commandes", icon: Truck, prefix: "CO" },
  avoir: { label: "Avoir", plural: "Avoirs", icon: Undo2, prefix: "AV" },
};

const CURRENCIES = {
  XOF: { symbol: "FCFA", decimals: 0 },
  XAF: { symbol: "FCFA", decimals: 0 },
  EUR: { symbol: "€", decimals: 2 },
  USD: { symbol: "$", decimals: 2 },
  GBP: { symbol: "£", decimals: 2 },
  CAD: { symbol: "$ CA", decimals: 2 },
};

function formatMoney(amount, currency) {
  const c = CURRENCIES[currency] || CURRENCIES.XOF;
  const n = new Intl.NumberFormat("fr-FR", {
    minimumFractionDigits: c.decimals,
    maximumFractionDigits: c.decimals,
  }).format(amount || 0);
  return `${n} ${c.symbol}`;
}

function formatDate(iso) {
  if (!iso) return "";
  const d = new Date(iso);
  if (isNaN(d)) return iso;
  return d.toLocaleDateString("fr-FR", { day: "2-digit", month: "2-digit", year: "numeric" });
}

function addDays(iso, days) {
  const d = new Date(iso);
  d.setDate(d.getDate() + days);
  return d.toISOString().slice(0, 10);
}

function computeTotals(doc) {
  const subtotal = (doc.items || []).reduce((s, i) => s + (Number(i.qty) || 0) * (Number(i.unitPrice) || 0), 0);
  const discountAmount = subtotal * ((doc.discountPercent || 0) / 100);
  const totalHT = subtotal - discountAmount;
  const taxAmount = totalHT * ((doc.taxRate || 0) / 100);
  const totalTTC = totalHT + taxAmount;
  const paid = doc.paymentStatus === "paid" ? totalTTC : (Number(doc.paidAmount) || 0);
  const remaining = Math.max(totalTTC - paid, 0);
  return { subtotal, discountAmount, totalHT, taxAmount, totalTTC, paid, remaining };
}

const STORAGE_KEY = "maline-factu-data";

const seedData = () => ({
  documents: [],
  clients: [
    { id: genId(), name: "Client Exemple", address: "", phone: "", email: "" },
  ],
  articles: [],
  settings: {
    companyName: "Maline Productions",
    companyAddress: "B.P. 260, PK 10, Bangui, Centrafrique",
    companyPhone: "+236 72 29 49 33 | +236 75 01 60 00",
    companyEmail: "malineproductions@gmail.com",
    companyWebsite: "www.malineproductions.com",
    currency: "XOF",
    taxRateDefault: 0,
    terms: "Merci de régler à réception de la facture.",
    numbering: { facture: 1, devis: 1, commande: 1, avoir: 1 },
  },
});

/* ---------------------------------- APP ------------------------------------ */
export default function App() {
  const [loaded, setLoaded] = useState(false);
  const [documents, setDocuments] = useState([]);
  const [clients, setClients] = useState([]);
  const [articles, setArticles] = useState([]);
  const [settings, setSettings] = useState(seedData().settings);
  const [saveState, setSaveState] = useState("idle"); // idle | saving | saved
  const [screen, setScreen] = useState({ name: "list", docType: "facture" });
  const [editingClient, setEditingClient] = useState(null); // null | {} | client
  const [editingArticle, setEditingArticle] = useState(null);
  const [previewDoc, setPreviewDoc] = useState(null);
  const firstLoad = useRef(true);
  const isRemoteUpdate = useRef(false);

  // Chargement initial depuis Supabase
  useEffect(() => {
    (async () => {
      try {
        const value = await getData(STORAGE_KEY);
        const data = value || seedData();
        setDocuments(data.documents || []);
        setClients(data.clients || []);
        setArticles(data.articles || []);
        setSettings({ ...seedData().settings, ...(data.settings || {}) });
      } catch (e) {
        const data = seedData();
        setDocuments(data.documents);
        setClients(data.clients);
        setArticles(data.articles);
        setSettings(data.settings);
      } finally {
        setLoaded(true);
      }
    })();
  }, []);

  // Abonnement temps réel : reçoit les changements faits depuis un autre appareil
  useEffect(() => {
    const unsubscribe = subscribeToChanges(STORAGE_KEY, (value) => {
      isRemoteUpdate.current = true;
      setDocuments(value.documents || []);
      setClients(value.clients || []);
      setArticles(value.articles || []);
      setSettings({ ...seedData().settings, ...(value.settings || {}) });
      setSaveState("synced");
    });
    return unsubscribe;
  }, []);

  // Sauvegarde (debounced) vers Supabase à chaque changement local
  useEffect(() => {
    if (!loaded) return;
    if (firstLoad.current) { firstLoad.current = false; return; }
    if (isRemoteUpdate.current) { isRemoteUpdate.current = false; return; }
    setSaveState("saving");
    const t = setTimeout(async () => {
      try {
        await setData(STORAGE_KEY, { documents, clients, articles, settings });
        setSaveState("synced");
      } catch (e) {
        setSaveState("error");
      }
    }, 500);
    return () => clearTimeout(t);
  }, [documents, clients, articles, settings, loaded]);

  const clientsById = useMemo(() => {
    const m = {};
    clients.forEach((c) => (m[c.id] = c));
    return m;
  }, [clients]);

  function createDocument(docType) {
    const num = settings.numbering[docType] || 1;
    const today = new Date().toISOString().slice(0, 10);
    const newDoc = {
      id: genId(),
      type: docType,
      number: num,
      date: today,
      dueDate: addDays(today, 30),
      clientId: clients[0] ? clients[0].id : "",
      title: "",
      discountPercent: 0,
      taxRate: settings.taxRateDefault || 0,
      paymentStatus: "unpaid",
      paidAmount: 0,
      items: [],
      notes: "",
      createdAt: Date.now(),
    };
    setDocuments((d) => [newDoc, ...d]);
    setSettings((s) => ({ ...s, numbering: { ...s.numbering, [docType]: num + 1 } }));
    setScreen({ name: "editor", docType, id: newDoc.id });
  }

  function updateDocument(id, patch) {
    setDocuments((docs) => docs.map((d) => (d.id === id ? { ...d, ...patch } : d)));
  }

  function deleteDocument(id) {
    setDocuments((docs) => docs.filter((d) => d.id !== id));
  }

  function saveClient(client) {
    if (client.id) {
      setClients((cs) => cs.map((c) => (c.id === client.id ? client : c)));
    } else {
      setClients((cs) => [...cs, { ...client, id: genId() }]);
    }
    setEditingClient(null);
  }

  function deleteClient(id) {
    setClients((cs) => cs.filter((c) => c.id !== id));
    setEditingClient(null);
  }

  function saveArticle(article) {
    if (article.id) {
      setArticles((as) => as.map((a) => (a.id === article.id ? article : a)));
    } else {
      setArticles((as) => [...as, { ...article, id: genId() }]);
    }
    setEditingArticle(null);
  }

  function deleteArticle(id) {
    setArticles((as) => as.filter((a) => a.id !== id));
    setEditingArticle(null);
  }

  if (!loaded) {
    return (
      <div className="w-full h-screen flex items-center justify-center" style={{ background: T.paper, fontFamily: FONT_BODY }}>
        <div className="text-sm" style={{ color: T.inkSoft }}>Chargement…</div>
      </div>
    );
  }

  return (
    <div className="w-full h-screen flex overflow-hidden" style={{ fontFamily: FONT_BODY, background: T.paper }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Fraunces:opsz,wght@9..144,500;9..144,600;9..144,700&family=Inter:wght@400;500;600;700&family=IBM+Plex+Mono:wght@400;500;600&display=swap');
        * { box-sizing: border-box; }
        ::selection { background: ${T.peach}; }
        .tabnum { font-variant-numeric: tabular-nums; }
        input:focus, textarea:focus, select:focus { outline: none; box-shadow: 0 0 0 2px ${T.peachBorder}; }
        @media print {
          .no-print { display: none !important; }
        }
      `}</style>

      <Sidebar
        active={screen.name === "list" ? screen.docType : screen.name}
        onNavigate={(name) => {
          if (DOC_META[name]) setScreen({ name: "list", docType: name });
          else setScreen({ name });
        }}
        saveState={saveState}
      />

      <div className="flex-1 h-full overflow-y-auto relative">
        {screen.name === "list" && (
          <ListScreen
            docType={screen.docType}
            documents={documents.filter((d) => d.type === screen.docType)}
            clientsById={clientsById}
            settings={settings}
            onOpen={(id) => setScreen({ name: "editor", docType: screen.docType, id })}
            onCreate={() => createDocument(screen.docType)}
            onDelete={deleteDocument}
          />
        )}

        {screen.name === "editor" && (
          <DocEditor
            doc={documents.find((d) => d.id === screen.id)}
            clients={clients}
            articles={articles}
            settings={settings}
            onChange={(patch) => updateDocument(screen.id, patch)}
            onDelete={() => {
              deleteDocument(screen.id);
              setScreen({ name: "list", docType: screen.docType });
            }}
            onBack={() => setScreen({ name: "list", docType: screen.docType })}
            onPreview={(doc) => setPreviewDoc(doc)}
            onAddClient={() => setEditingClient({})}
          />
        )}

        {screen.name === "clients" && (
          <ClientsScreen
            clients={clients}
            documents={documents}
            onEdit={(c) => setEditingClient(c)}
            onAdd={() => setEditingClient({})}
          />
        )}

        {screen.name === "articles" && (
          <ArticlesScreen
            articles={articles}
            currency={settings.currency}
            onEdit={(a) => setEditingArticle(a)}
            onAdd={() => setEditingArticle({})}
          />
        )}

        {screen.name === "settings" && (
          <SettingsScreen settings={settings} onChange={(patch) => setSettings((s) => ({ ...s, ...patch }))} />
        )}
      </div>

      {editingClient !== null && (
        <ClientPanel
          client={editingClient}
          onClose={() => setEditingClient(null)}
          onSave={saveClient}
          onDelete={editingClient.id ? () => deleteClient(editingClient.id) : null}
        />
      )}

      {editingArticle !== null && (
        <ArticlePanel
          article={editingArticle}
          currency={settings.currency}
          onClose={() => setEditingArticle(null)}
          onSave={saveArticle}
          onDelete={editingArticle.id ? () => deleteArticle(editingArticle.id) : null}
        />
      )}

      {previewDoc && (
        <PreviewModal
          doc={previewDoc}
          client={clientsById[previewDoc.clientId]}
          settings={settings}
          onClose={() => setPreviewDoc(null)}
        />
      )}
    </div>
  );
}

/* -------------------------------- SIDEBAR ----------------------------------- */
